// Serial Ports
package serialport

import (
	"context"

	"github.com/arminguenther/xeruspower-go/v40010/idl"
	"github.com/arminguenther/xeruspower-go/v40010/idl/event"
)

// Error codes
const (
	SUCCESS           int32 = 0 // No error
	ERR_INVALID_VALUE int32 = 1 // Invalid arguments
)

// Interface describing a physical serial port
// and the devices which can be attached to it
type SerialPort interface {
	idl.Object

	// Get port meta data
	//
	//	@return -- Meta data
	GetMetaData(ctx context.Context) (MetaData, error)

	// Get current settings
	//
	//	@return -- Settings
	GetSettings(ctx context.Context) (Settings, error)

	// Set settings
	//
	//	@param settings -- new settings
	//
	//	@return SUCCESS           -- on success
	//	@return ERR_INVALID_VALUE -- if any passed value was invalid
	SetSettings(ctx context.Context, settings Settings) (int32, error)

	// Get current port state
	//
	//	@return -- Port state
	GetState(ctx context.Context) (State, error)

	// Get modem connected to port
	//
	//	@return -- an instance of the connected modem (either
	//	           {@link AnalogModem} or {@link GsmModem})
	GetModem(ctx context.Context) (idl.Object, error)
}

// Possible states the port can be in at a given time
type PortState int

const (
	CONSOLE      PortState = iota // The console application is running on the port
	ANALOGMODEM                   // An analog modem is attached to the port
	GSMMODEM                      // A GSM modem is attached to the port
	DISCONNECTED                  // No device matching the configured mode is detected
)

// Device type the port shall be looking for
type DetectionType int

const (
	AUTOMATIC         DetectionType = iota // Try to automatically determine the connected device
	FORCE_CONSOLE                          // Always assume a console (terminal) is connected
	FORCE_ANALOGMODEM                      // Always assume an analog modem is connected
	FORCE_GSMMODEM                         // Always assume a GSM modem is connected
)

// Possible baud rates
type BaudRate int

const (
	BR1200   BaudRate = iota // 1.200 kbit/s
	BR2400                   // 2.400 kbit/s
	BR4800                   // 4.800 kbit/s
	BR9600                   // 9.600 kbit/s
	BR19200                  // 19.200 kbit/s
	BR38400                  // 38.400 kbit/s
	BR57600                  // 57.600 kbit/s
	BR115200                 // 115.200 kbit/s
)

// (Static) meta data containing port properties
type MetaData struct {
	// Whether or not the port can detect modems (if false,
	// this port can only operate in console mode)
	HasModemSupport bool
}

// Structure holding information about
// the current state of the port
type State struct {
	State      PortState // Current connection state
	DeviceName string    // Name of the device currently connected
}

// Port settings
type Settings struct {
	ConsoleBaudRate BaudRate      // Baud rate to be used for running the console application
	ModemBaudRate   BaudRate      // Baud rate to be used for communicating with an attached modem
	DetectType      DetectionType // Type of connected device to be assumed in device detection
}

// Event emitted when the modem connection state changes
type ModemEvent interface {
	event.Event
	Modem() idl.Object // Either a {@link AnalogModem} or a {@link GsmModem}
	isModemEvent()
}

// Event emitted when a modem is connected
type ModemAddedEvent interface {
	ModemEvent
	isModemAddedEvent()
}

// Event emitted when a modem is disconnected
type ModemRemovedEvent interface {
	ModemEvent
	isModemRemovedEvent()
}
